const HeroSlider: React.FC = () => {
  const [current, setCurrent] = useState(0);
  const [isPaused, setIsPaused] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const thumbRefs = useRef<(HTMLButtonElement | null)[]>([]);

  const startTimer = () => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(() => {
      if (!isPaused) {
        setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
      }
    }, 6000);
  };

  useEffect(() => {
    startTimer();
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isPaused]);

  // Sync scrolling of thumbnails
  useEffect(() => {
    const activeThumb = thumbRefs.current[current];
    if (activeThumb) {
      activeThumb.scrollIntoView({
        behavior: 'smooth',
        block: 'nearest',
        inline: 'center'
      });
    }
  }, [current]);

  const next = () => {
    setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
    startTimer();
  };

  const prev = () => {
    setCurrent((prev) => (prev === 0 ? slides.length - 1 : prev - 1));
    startTimer();
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement, Event>) => {
    e.currentTarget.src = "https://images.unsplash.com/photo-1505751172177-51ad18610432?auto=format&fit=crop&q=80&w=1920";
  };

  return (
    <section className="relative h-[650px] sm:h-[750px] lg:h-[850px] w-full overflow-hidden bg-gray-900 group">
      {/* Background Slides */}
      <div className="relative w-full h-full">
        {slides.map((slide, index) => (
          <div
            key={index}
            className={`absolute inset-0 transition-all duration-1000 ease-in-out ${
              index === current 
                ? 'opacity-100 z-10 translate-x-0 scale-100' 
                : 'opacity-0 z-0 translate-x-12 scale-105'
            }`}
          >
            <img
              src={slide.image}
              alt={slide.title}
              onError={handleImageError}
              loading={index === 0 ? "eager" : "lazy"}
              className={`w-full h-full object-cover object-center transition-transform duration-[12000ms] ease-linear transform ${index === current ? 'scale-115' : 'scale-100'}`}
            />
            {/* Immersive Gradient & Content */}
            <div className={`absolute inset-0 bg-gradient-to-r ${slide.color} flex items-center`}>
              <div className="container mx-auto px-6 md:px-12 text-white">
                <div className={`max-w-3xl transform transition-all duration-1000 delay-300 ${index === current ? 'translate-y-0 opacity-100' : 'translate-y-20 opacity-0'}`}>
                  <div className="flex items-center gap-3 mb-6">
                    <span className="inline-flex items-center gap-2 px-4 py-1.5 bg-white/10 backdrop-blur-md rounded-full text-xs font-black border border-white/20 animate-pulse uppercase tracking-wider">
                      <Zap size={14} className="text-yellow-400" />
                      عضوية أمان إيفر المميزة
                    </span>
                  </div>

                  <h1 className="text-5xl sm:text-6xl lg:text-8xl font-black mb-8 leading-[1.1] drop-shadow-2xl">
                    {slide.title}
                  </h1>

                  <p className="text-xl sm:text-2xl mb-12 text-gray-100 font-bold leading-relaxed opacity-90 max-w-2xl drop-shadow-lg">
                    {slide.description}
                  </p>

                  <div className="flex flex-col sm:flex-row gap-5">
                    <button className="px-14 py-5 bg-[#006666] text-white rounded-2xl font-black text-xl hover:bg-[#004d4d] transition-all shadow-[0_20px_50px_rgba(0,102,102,0.3)] hover:scale-105 active:scale-95 flex items-center justify-center gap-3 group/btn">
                      {slide.cta}
                      <ChevronLeft className="rtl-flip group-hover/btn:-translate-x-1 transition-transform" />
                    </button>
                    <button className="px-14 py-5 bg-white/10 backdrop-blur-md border-2 border-white/30 text-white rounded-2xl font-black text-xl hover:bg-white/20 transition-all hover:scale-105 active:scale-95">
                      اكتشف الشبكة
                    </button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modern Carousel Dashboard */}
      <div className="absolute bottom-12 left-0 right-0 z-30 container mx-auto px-4 md:px-6">
        <div className="flex flex-col lg:flex-row items-stretch lg:items-center justify-between gap-6 bg-black/30 backdrop-blur-2xl border border-white/10 p-6 rounded-[3rem] shadow-[0_35px_60px_-15px_rgba(0,0,0,0.5)]">

          {/* Enhanced Thumbnail Strip */}
          <div className="flex-grow flex items-center gap-4 overflow-x-auto no-scrollbar pb-1 mask-linear-fade scroll-smooth">
            {slides.map((slide, idx) => (
              <button
                key={idx}
                ref={el => thumbRefs.current[idx] = el}
                onClick={() => {
                  setCurrent(idx);
                  startTimer();
                }}
                className={`relative group shrink-0 w-32 h-20 sm:w-44 sm:h-24 rounded-2xl overflow-hidden border-2 transition-all duration-700 transform ${
                  idx === current 
                    ? 'border-white scale-105 shadow-2xl z-20' 
                    : 'border-white/10 opacity-30 hover:opacity-100 hover:scale-100'
                }`}
              >
                <img src={slide.image} className="w-full h-full object-cover" alt="" />
                <div className={`absolute inset-0 bg-black/40 transition-opacity duration-700 ${idx === current ? 'opacity-0' : 'opacity-60'}`} />

                {/* Thumb Overlay Info */}
                <div className="absolute inset-0 p-3 flex flex-col justify-end opacity-0 group-hover:opacity-100 transition-opacity bg-gradient-to-t from-black/80 to-transparent">
                   <p className="text-[10px] font-black text-white truncate text-right">0{idx + 1} الشريحة</p>
                </div>

                {idx === current && (
                   <div className="absolute bottom-0 left-0 right-0 h-1 bg-white origin-left animate-[progress_6s_linear]" />
                )}
              </button>
            ))}
          </div>

          {/* Integrated Control Panel */}
          <div className="flex items-center justify-between lg:justify-end gap-6 shrink-0 lg:pl-4 border-t lg:border-t-0 lg:border-r border-white/10 pt-4 lg:pt-0">
            <div className="flex items-center gap-4">
              <button 
                onClick={() => setIsPaused(!isPaused)}
                className="w-14 h-14 rounded-full bg-white/10 hover:bg-white/20 backdrop-blur-md text-white flex items-center justify-center transition-all shadow-xl active:scale-90 border border-white/10"
                title={isPaused ? "تشغيل" : "إيقاف مؤقت"}
              >
                {isPaused ? <Play size={24} fill="currentColor" /> : <Pause size={24} fill="currentColor" />}
              </button>

              <div className="hidden sm:flex flex-col text-white/60">
                <span className="text-[10px] font-black uppercase tracking-widest leading-none">تلقائي</span>
                <span className="text-xs font-bold">{isPaused ? 'متوقف' : 'نشط'}</span>
              </div>
            </div>

            <div className="flex gap-4">
              <button 
                onClick={prev} 
                className="w-14 h-14 rounded-2xl bg-white text-gray-900 hover:bg-teal-50 flex items-center justify-center transition-all hover:scale-110 active:scale-95 shadow-2xl"
                aria-label="السابق"
              >
                <ChevronRight className="w-7 h-7" />
              </button>
              <button 
                onClick={next} 
                className="w-14 h-14 rounded-2xl bg-white text-gray-900 hover:bg-teal-50 flex items-center justify-center transition-all hover:scale-110 active:scale-95 shadow-2xl"
                aria-label="التالي"
              >
                <ChevronLeft className="w-7 h-7" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Ambient HUD Background Particles */}
      <div className="absolute inset-0 pointer-events-none">
         <div className="absolute top-[-10%] right-[-10%] w-[50%] h-[50%] bg-blue-500/10 rounded-full blur-[120px] animate-pulse" />
         <div className="absolute bottom-[-10%] left-[-10%] w-[50%] h-[50%] bg-teal-500/10 rounded-full blur-[120px] animate-pulse delay-1000" />
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }

        @keyframes progress {
          from { transform: scaleX(0); }
          to { transform: scaleX(1); }
        }

        .mask-linear-fade {
          mask-image: linear-gradient(to left, black 85%, transparent 100%);
        }
      `}</style>
    </section>
  );
};

export default HeroSlider;

import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error?: Error;
}

// ErrorBoundary class component to catch rendering errors in children components.
// Fixed: Explicitly using React.Component and a constructor to ensure 'props' is properly typed and accessible on the instance.
class ErrorBoundary extends React.Component<Props, State> {
  // Added constructor to explicitly bind props and initialize state
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false
    };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error('Uncaught error:', error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-[400px] flex items-center justify-center p-8 bg-gray-50 rounded-[3rem] my-12 border-2 border-dashed border-gray-200">
          <div className="text-center max-w-md">
            <div className="inline-flex items-center justify-center w-20 h-20 rounded-full bg-red-50 text-red-600 mb-6">
              <AlertTriangle size={40} />
            </div>
            <h2 className="text-2xl font-black text-gray-900 mb-4">عذراً، حدث خطأ غير متوقع</h2>
            <p className="text-gray-500 font-bold mb-8">
              نواجه حالياً صعوبة في تحميل هذا الجزء. يرجى المحاولة مرة أخرى أو تحديث الصفحة.
            </p>
            <button
              onClick={() => window.location.reload()}
              className="px-8 py-3 bg-blue-600 text-white rounded-full font-black flex items-center justify-center gap-3 mx-auto hover:bg-blue-700 transition-all shadow-lg"
            >
              <RefreshCw size={20} /> إعادة تحميل الصفحة
            </button>
          </div>
        </div>
      );
    }

    // Accessing children from this.props which is now correctly recognized by extending React.Component and using super(props)
    return this.props.children;
  }
}

export default ErrorBoundary;
